/**
 * Per-station batch-cap test.
 *
 * Validates that Pipeline's chunkSize clamp now reads `IStation.maxBatchSize`
 * (per-station, optional) instead of the old hard-coded `BATCH_CAP_SAFE = 4`.
 *
 * Behavior matrix (Station 2026-04-26 update — `Station` HTTP class is
 * wasm-safe-by-default at 4; UDS/Flow/FlowUdp keep 8; `Station` callers may
 * opt up to 8 via `maxBatchSize: 8` in the constructor config):
 *   - all stations declare 8                        → cap = 8 (all-UDS mesh /
 *                                                     all-native StationFlow)
 *   - mixed: one station declares 4 (e.g. `Station`
 *     fronting a CF Worker, OR an explicit wasm
 *     leg), other(s) declare 8                      → cap = 4 (min, the
 *                                                     wasm-bounded leg forces
 *                                                     the whole chain down)
 *   - no station declares it                        → cap = 4 (backward-
 *                                                     compatible safety floor
 *                                                     for pre-2026-04-26
 *                                                     IStation impls)
 *
 * The throughput payoff is observable as a chunk-count drop: a 30-token
 * prompt across 2 native UDS stations chunks into ceil(30/8) = 4 round-trips,
 * versus ceil(30/4) = 8 on any chain that includes a wasm-bounded leg
 * (including the `Station` HTTP default). ~2x fewer per-prefill hops on
 * known-all-native meshes.
 *
 * Reference: docs/pneuma/per-station-batch-cap.md
 */

import { describe, expect, it } from 'vitest';

import { Pipeline } from '../pipeline';
import type { IStation } from '../types';

const HIDDEN_DIM = 4;
const VOCAB = 8;

interface RecordedCall {
  kind: 'embed' | 'forward' | 'lmHead' | 'sampleNext' | 'decodeNext';
  startPos: number;
  sequenceLength: number;
}

/**
 * Minimal IStation stub. Replies with a deterministic Float32Array sized to
 * `sequenceLength * HIDDEN_DIM`, lets us count `forward()` invocations and
 * inspect each chunk's `sequenceLength` without a real wire.
 */
function buildStubStation(opts: {
  startLayer: number;
  endLayer: number;
  role?: 'entry' | 'mid' | 'exit';
  /** When undefined, the field is omitted (back-compat path). */
  maxBatchSize?: number;
  sampleNextToken?: number;
  decodeNextToken?: number;
}): { station: IStation; calls: RecordedCall[] } {
  const calls: RecordedCall[] = [];
  const sampleNextToken = opts.sampleNextToken;
  const decodeNextToken = opts.decodeNextToken;

  const station: IStation = {
    startLayer: opts.startLayer,
    endLayer: opts.endLayer,
    role: opts.role,
    ...(opts.maxBatchSize !== undefined ? { maxBatchSize: opts.maxBatchSize } : {}),

    async embed({ tokens, startPos }) {
      calls.push({ kind: 'embed', startPos, sequenceLength: tokens.length });
      const out = new Float32Array(tokens.length * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) out[i] = (i + 1) * 0.001;
      return out;
    },

    async forward({ residual, startPos, sequenceLength }) {
      calls.push({ kind: 'forward', startPos, sequenceLength });
      const out = new Float32Array(sequenceLength * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) out[i] = (residual[i] ?? 0) + 0.01;
      return { residual: out };
    },

    async lmHead({ residual, sequenceLength }) {
      calls.push({ kind: 'lmHead', startPos: 0, sequenceLength });
      const out = new Float32Array(VOCAB);
      out[3] = 1; // argmax = 3
      return out;
    },

    ...(sampleNextToken !== undefined
      ? {
          async sampleNext({
            sequenceLength,
          }: {
            residual: Float32Array;
            sequenceLength: number;
            requestId?: string;
          }) {
            calls.push({ kind: 'sampleNext', startPos: 0, sequenceLength });
            return sampleNextToken;
          },
        }
      : {}),

    ...(decodeNextToken !== undefined
      ? {
          async decodeNext({
            position,
          }: {
            tokenId: number;
            position: number;
            requestId?: string;
          }) {
            calls.push({ kind: 'decodeNext', startPos: position, sequenceLength: 1 });
            return decodeNextToken;
          },
        }
      : {}),

    async cobordismEmbed() {
      throw new Error('not used');
    },
    async cobordismLmHead() {
      throw new Error('not used');
    },
    async bizarroForward() {
      return null;
    },
  };

  return { station, calls };
}

function makePipeline(stations: IStation[]): Pipeline {
  return new Pipeline({
    stations,
    hiddenDim: HIDDEN_DIM,
    vocabSize: VOCAB,
  });
}

/** Promote test prompt + expected per-chunk seq-lens into one assertion. */
function expectChunkPattern(
  forwards: RecordedCall[],
  expectedSeqLens: number[],
): void {
  const got = forwards.map((c) => c.sequenceLength);
  expect(got).toEqual(expectedSeqLens);
}

describe('Pipeline chunkSize clamp — per-station maxBatchSize', () => {
  it('all-UDS-style stations (maxBatchSize=8) → cap = 8', async () => {
    // 30-token prompt across 2 native UDS-style stations (UDS/Flow/FlowUdp
    // all hard-declare 8). The HTTP `Station` class defaults to 4 because
    // it may front a CF Worker, so this scenario models an all-native mesh
    // (e.g. StationUds + StationUds, or StationFlow + StationFlow).
    // floor(30/2)=15, clamped to min(8,15)=8 → chunks of [8,8,8,6].
    const s0 = buildStubStation({
      startLayer: 0,
      endLayer: 4,
      role: 'entry',
      maxBatchSize: 8,
    });
    const s1 = buildStubStation({
      startLayer: 4,
      endLayer: 8,
      role: 'exit',
      maxBatchSize: 8,
    });
    const pipe = makePipeline([s0.station, s1.station]);

    const promptTokens = new Uint32Array(30).map((_, i) => i + 1);
    await pipe.pipelinedPrefill({ promptTokens });

    const s0Forwards = s0.calls.filter((c) => c.kind === 'forward');
    expectChunkPattern(s0Forwards, [8, 8, 8, 6]);
    expect(s0Forwards.length).toBe(4); // 30/8 → 4 chunks
  });

  it('mixed mesh (HTTP Station @4 default + UDS @8) → cap = min = 4', async () => {
    // Same 30-token prompt. The HTTP `Station` class defaults to 4 (wasm-
    // safe — may front a CF Worker), so any mesh that mixes a Station with
    // UDS/Flow legs clamps the whole chain to 4. Models a coordinator that
    // hops Station(HTTP/CF Worker) → StationUds(native) → StationUds(native).
    // Result: chunks of [4,4,4,4,4,4,4,2] = 8 chunks.
    const s0 = buildStubStation({
      startLayer: 0,
      endLayer: 4,
      role: 'entry',
      maxBatchSize: 4, // HTTP Station default — possibly fronting a CF Worker
    });
    const s1 = buildStubStation({
      startLayer: 4,
      endLayer: 8,
      maxBatchSize: 8, // UDS-style native leg
    });
    const s2 = buildStubStation({
      startLayer: 8,
      endLayer: 12,
      role: 'exit',
      maxBatchSize: 8, // UDS-style native leg
    });
    const pipe = makePipeline([s0.station, s1.station, s2.station]);

    const promptTokens = new Uint32Array(30).map((_, i) => i + 1);
    await pipe.pipelinedPrefill({ promptTokens });

    const s0Forwards = s0.calls.filter((c) => c.kind === 'forward');
    expectChunkPattern(s0Forwards, [4, 4, 4, 4, 4, 4, 4, 2]);
    expect(s0Forwards.length).toBe(8); // 30/4 → 8 chunks
  });

  it('no maxBatchSize declared → backward-compatible safety floor of 4', async () => {
    // Stations omit `maxBatchSize` (pre-2026-04-26 implementations).
    // The `?? 4` fallback keeps these on the wasm-safe cap.
    const s0 = buildStubStation({ startLayer: 0, endLayer: 4, role: 'entry' });
    const s1 = buildStubStation({ startLayer: 4, endLayer: 8, role: 'exit' });
    const pipe = makePipeline([s0.station, s1.station]);

    const promptTokens = new Uint32Array(30).map((_, i) => i + 1);
    await pipe.pipelinedPrefill({ promptTokens });

    const s0Forwards = s0.calls.filter((c) => c.kind === 'forward');
    expectChunkPattern(s0Forwards, [4, 4, 4, 4, 4, 4, 4, 2]);
    expect(s0Forwards.length).toBe(8);
  });

  it('omits full station residual capture unless requested', async () => {
    const s0 = buildStubStation({
      startLayer: 0,
      endLayer: 4,
      role: 'entry',
      maxBatchSize: 8,
    });
    const s1 = buildStubStation({
      startLayer: 4,
      endLayer: 8,
      role: 'exit',
      maxBatchSize: 8,
    });
    const pipe = makePipeline([s0.station, s1.station]);

    const promptTokens = new Uint32Array(12).map((_, i) => i + 1);
    const noCapture = await pipe.pipelinedPrefill({ promptTokens });
    expect(noCapture.stationPrefixResiduals).toBeUndefined();

    const withCapture = await pipe.pipelinedPrefill({
      promptTokens,
      captureStationResiduals: true,
    });
    expect(withCapture.stationPrefixResiduals).toHaveLength(2);
    expect(withCapture.stationPrefixResiduals?.[0]?.length).toBe(
      promptTokens.length * HIDDEN_DIM,
    );
    expect(withCapture.stationPrefixResiduals?.[1]?.length).toBe(
      promptTokens.length * HIDDEN_DIM,
    );
  });

  it('uses native sampleNext for greedy decode after prefill', async () => {
    const s0 = buildStubStation({
      startLayer: 0,
      endLayer: 8,
      maxBatchSize: 8,
      sampleNextToken: 4,
    });
    const pipe = makePipeline([s0.station]);

    const promptTokens = new Uint32Array([1, 2]);
    const out = await pipe.generate({ promptTokens, maxNewTokens: 3 });

    expect(Array.from(out.slice(promptTokens.length))).toEqual([3, 4, 4]);
    expect(s0.calls.filter((c) => c.kind === 'lmHead')).toHaveLength(1);
    expect(s0.calls.filter((c) => c.kind === 'sampleNext')).toHaveLength(2);
  });

  it('uses native decodeNext before residual sampleNext on a single station', async () => {
    const s0 = buildStubStation({
      startLayer: 0,
      endLayer: 8,
      maxBatchSize: 8,
      sampleNextToken: 4,
      decodeNextToken: 5,
    });
    const pipe = makePipeline([s0.station]);

    const promptTokens = new Uint32Array([1, 2]);
    const out = await pipe.generate({ promptTokens, maxNewTokens: 3 });

    expect(Array.from(out.slice(promptTokens.length))).toEqual([3, 5, 5]);
    expect(s0.calls.filter((c) => c.kind === 'lmHead')).toHaveLength(1);
    expect(s0.calls.filter((c) => c.kind === 'decodeNext')).toHaveLength(2);
    expect(s0.calls.filter((c) => c.kind === 'sampleNext')).toHaveLength(0);
  });
});
